import{_ as t,o as h,c as i,a0 as o}from"./chunks/framework.jwovEGr5.js";const s=JSON.parse('{"title":"Giới thiệu về ABNERP","description":"","frontmatter":{"title":"Giới thiệu về ABNERP"},"headers":[],"relativePath":"introduction.md","filePath":"introduction.md"}'),a={name:"introduction.md"};function r(g,n,c,d,e,l){return h(),i("div",null,[...n[0]||(n[0]=[o('<h1 id="gioi-thieu-ve-abnerp" tabindex="-1">Giới thiệu về ABNERP <a class="header-anchor" href="#gioi-thieu-ve-abnerp" aria-label="Permalink to &quot;Giới thiệu về ABNERP&quot;">​</a></h1><h2 id="abnerp-la-gi" tabindex="-1">ABNERP là gì? <a class="header-anchor" href="#abnerp-la-gi" aria-label="Permalink to &quot;ABNERP là gì?&quot;">​</a></h2><p><strong>ABNERP</strong> là phần mềm quản lý doanh nghiệp toàn diện, được thiết kế để giúp doanh nghiệp vừa và nhỏ vận hành hiệu quả hơn. ABNERP cung cấp một bộ công cụ đầy đủ cho phép bạn:</p><ul><li><strong>Theo dõi tồn kho</strong> — Quản lý hàng hóa, nguyên vật liệu, thành phẩm theo thời gian thực</li><li><strong>Quản lý tài chính</strong> — Hạch toán kế toán, quản lý công nợ, dòng tiền</li><li><strong>Xử lý dự án</strong> — Lập kế hoạch, phân công nhiệm vụ, theo dõi tiến độ</li><li><strong>Chăm sóc khách hàng</strong> — Quản lý tương tác, hợp đồng, ticket hỗ trợ</li></ul><p>ABNERP đóng vai trò như <strong>hệ thống thần kinh trung ương</strong> cho doanh nghiệp của bạn — nơi mọi dữ liệu và quy trình được kết nối, đồng bộ và tự động hóa.</p><h2 id="tai-sao-chon-abnerp" tabindex="-1">Tại sao chọn ABNERP? <a class="header-anchor" href="#tai-sao-chon-abnerp" aria-label="Permalink to &quot;Tại sao chọn ABNERP?&quot;">​</a></h2><h3 id="bo-cong-cu-hoan-chinh" tabindex="-1">Bộ công cụ hoàn chỉnh <a class="header-anchor" href="#bo-cong-cu-hoan-chinh" aria-label="Permalink to &quot;Bộ công cụ hoàn chỉnh&quot;">​</a></h3><p>Không cần tích hợp nhiều phần mềm rời rạc. ABNERP cung cấp tất cả các mô-đun nghiệp vụ thiết yếu trong một nền tảng duy nhất: kế toán, bán hàng, mua hàng, kho vận, sản xuất, nhân sự, CRM và hỗ trợ.</p><h3 id="de-su-dung" tabindex="-1">Dễ sử dụng <a class="header-anchor" href="#de-su-dung" aria-label="Permalink to &quot;Dễ sử dụng&quot;">​</a></h3><p>Giao diện trực quan, thân thiện với người dùng, được thiết kế để giảm thiểu thời gian đào tạo. Hầu hết người dùng có thể bắt đầu làm việc chỉ sau vài giờ làm quen.</p><h3 id="chi-phi-hop-ly" tabindex="-1">Chi phí hợp lý <a class="header-anchor" href="#chi-phi-hop-ly" aria-label="Permalink to &quot;Chi phí hợp lý&quot;">​</a></h3><p>Chi phí sở hữu thấp hơn đáng kể so với các giải pháp ERP thương mại. Bạn chỉ trả cho những gì bạn sử dụng, không có phí giấy phép đắt đỏ.</p><h2 id="tinh-nang-chinh" tabindex="-1">Tính năng chính <a class="header-anchor" href="#tinh-nang-chinh" aria-label="Permalink to &quot;Tính năng chính&quot;">​</a></h2><p>ABNERP cung cấp hơn <strong>12 mô-đun tính năng</strong> chính:</p><table tabindex="0"><thead><tr><th>Tính năng</th><th>Mô tả</th></tr></thead><tbody><tr><td><strong>Theo dõi tài chính</strong></td><td>Sổ cái, sổ quỹ, công nợ phải thu/phải trả, báo cáo tài chính</td></tr><tr><td><strong>Hóa đơn</strong></td><td>Tạo và quản lý hóa đơn bán hàng, hóa đơn mua hàng, hóa đơn điện tử</td></tr><tr><td><strong>Quản lý tồn kho</strong></td><td>Nhập kho, xuất kho, chuyển kho, kiểm kê, định giá tồn kho</td></tr><tr><td><strong>KPI và Báo cáo</strong></td><td>Bảng điều khiển (dashboard), biểu đồ, báo cáo tùy chỉnh</td></tr><tr><td><strong>Chăm sóc khách hàng</strong></td><td>Quản lý ticket, SLA, cơ sở tri thức</td></tr><tr><td><strong>Quản lý lương</strong></td><td>Bảng lương, chấm công, bảo hiểm, thuế TNCN</td></tr><tr><td><strong>Quản lý dự án</strong></td><td>Kế hoạch dự án, nhiệm vụ, biểu đồ Gantt</td></tr><tr><td><strong>Tự động hóa</strong></td><td>Quy trình làm việc (workflow), tự động hóa email, nhắc nhở</td></tr><tr><td><strong>Quản lý tài liệu</strong></td><td>Đính kèm file, phiên bản tài liệu, chia sẻ</td></tr><tr><td><strong>Quản trị truy cập</strong></td><td>Phân quyền người dùng, vai trò, cấp độ truy cập</td></tr><tr><td><strong>Đa công ty</strong></td><td>Quản lý nhiều công ty trên cùng một hệ thống</td></tr><tr><td><strong>Đa tiền tệ</strong></td><td>Hỗ trợ giao dịch đa tiền tệ, tỷ giá hối đoái</td></tr></tbody></table><p>Xem hướng dẫn chi tiết tại trang <a href="/abnerp/setting-up.html">Thiết lập ABNERP</a>.</p><h2 id="cong-đong" tabindex="-1">Cộng đồng <a class="header-anchor" href="#cong-đong" aria-label="Permalink to &quot;Cộng đồng&quot;">​</a></h2><p>ABNERP có một cộng đồng người dùng và nhà phát triển năng động. Bạn có thể:</p><ul><li>Đặt câu hỏi trên diễn đàn cộng đồng</li><li>Tham gia các nhóm thảo luận trực tuyến</li><li>Đề xuất tính năng và báo cáo lỗi</li></ul>',19)])])}const p=t(a,[["render",r]]);export{s as __pageData,p as default};
